// Model-specific text (title, description, Learn intro/principle/tips) for the
// languages added after the models were authored: fr, de, ko, pt, es, ar, ru.
// English/Chinese/Japanese live on the model definitions themselves; this map
// supplies the newer languages, with English as the fallback. Each language is
// optional per model — missing translations fall back to English.
import type { Lang } from './index';
import type { ModelDefinition } from '../types/model';

type NewLang = 'fr' | 'de' | 'ko' | 'pt' | 'es' | 'ar' | 'ru';
export interface MLEntry {
  title: string;
  description: string;
  intro: string;
  principle: string;
  tips: string[];
}

export const modelText: Record<string, Partial<Record<NewLang, MLEntry>>> = {};

export function tModelTitle(lang: Lang, m: ModelDefinition): string {
  if (lang === 'zh') return m.meta.titleZh;
  if (lang === 'ja') return m.meta.titleJa ?? m.meta.title;
  const e = modelText[m.meta.id]?.[lang as NewLang];
  return e?.title ?? m.meta.title;
}

export function tModelDesc(lang: Lang, m: ModelDefinition): string {
  if (lang === 'zh') return m.meta.descriptionZh;
  if (lang === 'ja') return m.meta.descriptionJa ?? m.meta.description;
  const e = modelText[m.meta.id]?.[lang as NewLang];
  return e?.description ?? m.meta.description;
}

export interface LearnText { intro: string; principle: string; tips: string[] }

export function tLearn(lang: Lang, m: ModelDefinition): LearnText | null {
  const L = m.learn;
  if (!L) return null;
  if (lang === 'zh') return { intro: L.intro.zh, principle: L.principle.zh, tips: L.tips.map((t) => t.zh) };
  if (lang === 'ja') return { intro: L.intro.ja ?? L.intro.en, principle: L.principle.ja ?? L.principle.en, tips: L.tips.map((t) => t.ja ?? t.en) };
  const e = modelText[m.meta.id]?.[lang as NewLang];
  if (e) return { intro: e.intro, principle: e.principle, tips: e.tips };
  return { intro: L.intro.en, principle: L.principle.en, tips: L.tips.map((t) => t.en) };
}

